import React from "react";

function AuditTable({ data }) {

  if (!data) return null;

  return (
    <div>

      <h2>MRD Audit Result</h2>

      <h3>Compliance Score: {data.compliance_score}%</h3>

      <table border="1" cellPadding="10">

        <thead>
          <tr>
            <th>Checklist Item</th>
            <th>Status</th>
          </tr>
        </thead>

        <tbody>

          {data.audit_result.map((item, index) => (

            <tr key={index}>

              <td>{item.item}</td>

              <td
                style={{
                  color: item.status === "Present" ? "green" : "red"
                }}
              >
                {item.status}
              </td>

            </tr>

          ))}

        </tbody>

      </table>

    </div>
  );
}

export default AuditTable;
